import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum Role {
  ADMIN = 'Admin',
  FIELD_STAFF = 'Field Staff',
  PROJECT_STAFF = 'Project Staff'
}

export enum WorkStatus {
  WORKING = 'Working',
  LEAVE = 'Leave',
  HOLIDAY = 'Holiday'
}

export interface User {
  username: string;
  role: Role;
  createdDate?: string;
  password?: string;
}

export interface WorkLog {
  date: string;
  username: string;
  village: string;
  activity: string;
  workDetails: string;
  status: WorkStatus;
  reason?: string;
  timestamp?: string;
  photoUrl?: string;
  location?: string;
}

export interface GalleryItem {
  imageUrl: string;
  activity: string;
  village: string;
  date: string;
}

export interface AuthState {
  user: User | null;
  isAuthenticated: boolean;
}

import React, { useState, useEffect, createContext, useContext } from 'react';
import { HashRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import { AuthState, User, Role } from './types';
import Navbar from './components/Navbar';
import HomePage from './pages/HomePage';
import LoginPage from './pages/LoginPage';
import StaffDashboard from './pages/StaffDashboard';
import AdminDashboard from './pages/AdminDashboard';
import LogWorkForm from './pages/LogWorkForm';
import ReportsPage from './pages/ReportsPage';
import UserManagement from './pages/UserManagement';

interface AuthContextType {
  auth: AuthState;
  login: (user: User) => void;
  logout: () => void;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

export const useAuth = () => {
  const context = useContext(AuthContext);
  if (!context) throw new Error("useAuth must be used within AuthProvider");
  return context;
};

const ProtectedRoute = ({ children, allowedRoles }: { children: React.ReactNode, allowedRoles?: Role[] }) => {
  const { auth } = useAuth();
  if (!auth.isAuthenticated) return <Navigate to="/login" />;
  if (allowedRoles && auth.user && !allowedRoles.includes(auth.user.role)) return <Navigate to="/" />;
  return <>{children}</>;
};

const App: React.FC = () => {
  const [auth, setAuth] = useState<AuthState>(() => {
    const saved = localStorage.getItem('wassan_auth');
    return saved ? JSON.parse(saved) : { user: null, isAuthenticated: false };
  });

  const login = (user: User) => {
    const newState = { user, isAuthenticated: true };
    setAuth(newState);
    localStorage.setItem('wassan_auth', JSON.stringify(newState));
  };

  const logout = () => {
    setAuth({ user: null, isAuthenticated: false });
    localStorage.removeItem('wassan_auth');
  };

  return (
    <AuthContext.Provider value={{ auth, login, logout }}>
      <Router>
        <div className="min-h-screen flex flex-col">
          <Navbar />
          <main className="flex-grow">
            <Routes>
              <Route path="/" element={<HomePage />} />
              <Route path="/login" element={auth.isAuthenticated ? <Navigate to="/dashboard" /> : <LoginPage />} />

              <Route path="/dashboard" element={
                <ProtectedRoute>
                  {auth.user?.role === Role.ADMIN ? <AdminDashboard /> : <StaffDashboard />}
                </ProtectedRoute>
              } />

              <Route path="/log-work" element={
                <ProtectedRoute allowedRoles={[Role.FIELD_STAFF, Role.PROJECT_STAFF, Role.ADMIN]}>
                  <LogWorkForm />
                </ProtectedRoute>
              } />

              <Route path="/reports" element={
                <ProtectedRoute>
                  <ReportsPage />
                </ProtectedRoute>
              } />

              <Route path="/admin/users" element={
                <ProtectedRoute allowedRoles={[Role.ADMIN]}>
                  <UserManagement />
                </ProtectedRoute>
              } />

              <Route path="*" element={<Navigate to="/" />} />
            </Routes>
          </main>
          <footer className="bg-slate-900 text-white py-6 text-center text-sm">
            <p>&copy; 2024 Wassan Vikarabad Field Operations Monitoring. All Rights Reserved.</p>
          </footer>
        </div>
      </Router>
    </AuthContext.Provider>
  );
};

export default App;

import { User, WorkLog, Role, WorkStatus } from '../types';

/**
 * GOOGLE APPS SCRIPT BACKEND SETUP INSTRUCTIONS:
 * 1. Create a Google Sheet with tabs: "Users", "Work_Log", "Gallery".
 * 2. In Users sheet: Username, Password, Role, Created Date.
 * 3. In Work_Log sheet: Date, Username, Village, Activity, Work Details, Status, Reason, Timestamp, PhotoUrl, Location.
 * 4. Open Extensions > Apps Script.
 * 5. Paste the provided backend code (see bottom of this file in comments).
 * 6. Deploy as Web App (Execute as: Me, Access: Anyone).
 * 7. Copy the URL and paste it in the GAS_WEBAPP_URL below.
 */

// Placeholder URL. In a real app, this should be your deployed Apps Script URL.
const GAS_WEBAPP_URL = "https://script.google.com/macros/s/AKfycbz_example_gas_id/exec";

// Local storage fallback for demonstration if no GAS URL is provided
const isMockMode = !GAS_WEBAPP_URL.includes("macros/s/");

export const apiService = {
  async login(username: string, password: string): Promise<User | null> {
    if (isMockMode) {
      // Mock Data
      const mockUsers = JSON.parse(localStorage.getItem('mock_users') || '[]');
      if (username === 'admin' && password === 'admin') return { username: 'admin', role: Role.ADMIN };
      const user = mockUsers.find((u: any) => u.username === username && u.password === password);
      return user ? { username: user.username, role: user.role } : null;
    }

    try {
      const resp = await fetch(`${GAS_WEBAPP_URL}?action=login&username=${encodeURIComponent(username)}&password=${encodeURIComponent(password)}`);
      const data = await resp.json();
      return data.success ? data.user : null;
    } catch (err) {
      console.error("Login Error:", err);
      return null;
    }
  },

  async logWork(log: WorkLog): Promise<boolean> {
    if (isMockMode) {
      const logs = JSON.parse(localStorage.getItem('mock_logs') || '[]');
      logs.push({ ...log, timestamp: new Date().toISOString() });
      localStorage.setItem('mock_logs', JSON.stringify(logs));
      return true;
    }

    try {
      const resp = await fetch(GAS_WEBAPP_URL, {
        method: 'POST',
        body: JSON.stringify({ action: 'logWork', ...log })
      });
      const data = await resp.json();
      return data.success;
    } catch (err) {
      console.error("Log Work Error:", err);
      return false;
    }
  },

  async getAttendance(username: string, month: number, year: number): Promise<WorkLog[]> {
    if (isMockMode) {
      const logs = JSON.parse(localStorage.getItem('mock_logs') || '[]');
      return logs.filter((l: WorkLog) => {
        const d = new Date(l.date);
        return l.username === username && (d.getMonth() + 1) === month && d.getFullYear() === year;
      });
    }

    try {
      const resp = await fetch(`${GAS_WEBAPP_URL}?action=getAttendance&username=${username}&month=${month}&year=${year}`);
      const data = await resp.json();
      return data.logs || [];
    } catch (err) {
      return [];
    }
  },

  async getAllLogs(): Promise<WorkLog[]> {
    if (isMockMode) {
      return JSON.parse(localStorage.getItem('mock_logs') || '[]');
    }
    const resp = await fetch(`${GAS_WEBAPP_URL}?action=getAllLogs`);
    const data = await resp.json();
    return data.logs || [];
  },

  async addUser(user: User): Promise<boolean> {
    if (isMockMode) {
      const users = JSON.parse(localStorage.getItem('mock_users') || '[]');
      users.push({ ...user, createdDate: new Date().toISOString() });
      localStorage.setItem('mock_users', JSON.stringify(users));
      return true;
    }
    const resp = await fetch(GAS_WEBAPP_URL, {
      method: 'POST',
      body: JSON.stringify({ action: 'addUser', ...user })
    });
    const data = await resp.json();
    return data.success;
  },

  async getAllUsers(): Promise<User[]> {
    if (isMockMode) {
      const users = JSON.parse(localStorage.getItem('mock_users') || '[]');
      return [{ username: 'admin', role: Role.ADMIN }, ...users];
    }
    const resp = await fetch(`${GAS_WEBAPP_URL}?action=getUsers`);
    const data = await resp.json();
    return data.users || [];
  }
};

