import { GoogleGenAI } from "@google/genai";
import { WorkLog } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const geminiService = {
  async analyzeWorkLogs(logs: WorkLog[], userName: string): Promise<string> {
    if (!logs.length) return "No data available for analysis.";

    const context = logs.map(l => 
      `Date: ${l.date}, Village: ${l.village}, Activity: ${l.activity}, Details: ${l.workDetails}, Status: ${l.status}`
    ).join('\n');

    try {
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Analyze the following field activity logs for ${userName} and provide a professional performance summary, highlighting key accomplishments and identifying any patterns in activities or village coverage. Keep it under 150 words.\n\nLogs:\n${context}`,
        config: {
          systemInstruction: "You are an expert field operations analyst. Provide insightful, constructive feedback based on data."
        }
      });
      return response.text || "Unable to generate analysis at this time.";
    } catch (err) {
      console.error("Gemini Error:", err);
      return "AI analysis is currently unavailable.";
    }
  }
};

import React, { useState } from 'react';
import { Link, useNavigate, useLocation } from 'react-router-dom';
import { useAuth } from '../App';
import { Role } from '../types';

const Navbar: React.FC = () => {
  const { auth, logout } = useAuth();
  const navigate = useNavigate();
  const location = useLocation();
  const [isMenuOpen, setIsMenuOpen] = useState(false);

  const handleLogout = () => {
    logout();
    navigate('/login');
  };

  const navLinks = [
    { name: 'Home', path: '/' },
    { name: 'Gallery', path: '/', hash: '#gallery' },
    { name: 'Dashboard', path: '/dashboard', private: true },
    { name: 'Log Work', path: '/log-work', private: true },
    { name: 'Reports', path: '/reports', private: true },
    { name: 'Users', path: '/admin/users', private: true, role: Role.ADMIN },
  ];

  const filteredLinks = navLinks.filter(link => {
    if (!link.private) return true;
    if (link.private && !auth.isAuthenticated) return false;
    if (link.role && auth.user?.role !== link.role) return false;
    return true;
  });

  return (
    <nav className="bg-white border-b sticky top-0 z-50 no-print">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex justify-between h-16">
          <div className="flex items-center">
            <Link to="/" className="flex items-center space-x-2">
              <div className="w-10 h-10 bg-indigo-600 rounded-lg flex items-center justify-center text-white font-bold text-xl">
                W
              </div>
              <span className="text-xl font-bold tracking-tight text-indigo-900 hidden sm:block">Wassan Vikarabad</span>
            </Link>
          </div>

          <div className="hidden md:flex items-center space-x-4">
            {filteredLinks.map((link) => (
              <Link
                key={link.path + (link.hash || '')}
                to={link.path}
                className={`px-3 py-2 rounded-md text-sm font-medium transition-colors ${
                  location.pathname === link.path ? 'text-indigo-600 bg-indigo-50' : 'text-slate-600 hover:text-indigo-600 hover:bg-slate-50'
                }`}
              >
                {link.name}
              </Link>
            ))}
            {auth.isAuthenticated ? (
              <div className="flex items-center space-x-4 ml-4 pl-4 border-l">
                <div className="text-right leading-none">
                  <div className="text-sm font-semibold text-slate-900">{auth.user?.username}</div>
                  <div className="text-xs text-slate-500">{auth.user?.role}</div>
                </div>
                <button
                  onClick={handleLogout}
                  className="p-2 text-slate-400 hover:text-red-500 transition-colors"
                >
                  <i className="fas fa-sign-out-alt"></i>
                </button>
              </div>
            ) : (
              <Link
                to="/login"
                className="ml-4 px-4 py-2 bg-indigo-600 text-white rounded-lg text-sm font-medium hover:bg-indigo-700 transition-colors"
              >
                Sign In
              </Link>
            )}
          </div>

          <div className="md:hidden flex items-center">
            <button
              onClick={() => setIsMenuOpen(!isMenuOpen)}
              className="p-2 text-slate-600"
            >
              <i className={`fas ${isMenuOpen ? 'fa-times' : 'fa-bars'} text-xl`}></i>
            </button>
          </div>
        </div>
      </div>

      {isMenuOpen && (
        <div className="md:hidden bg-white border-b">
          <div className="px-2 pt-2 pb-3 space-y-1">
            {filteredLinks.map((link) => (
              <Link
                key={link.name}
                to={link.path}
                onClick={() => setIsMenuOpen(false)}
                className="block px-3 py-2 rounded-md text-base font-medium text-slate-600 hover:text-indigo-600 hover:bg-slate-50"
              >
                {link.name}
              </Link>
            ))}
            {auth.isAuthenticated ? (
              <button
                onClick={handleLogout}
                className="block w-full text-left px-3 py-2 rounded-md text-base font-medium text-red-600 hover:bg-red-50"
              >
                Sign Out
              </button>
            ) : (
              <Link
                to="/login"
                onClick={() => setIsMenuOpen(false)}
                className="block px-3 py-2 rounded-md text-base font-medium text-indigo-600 hover:bg-indigo-50"
              >
                Sign In
              </Link>
            )}
          </div>
        </div>
      )}
    </nav>
  );
};

export default Navbar;

import React from 'react';
import { WorkLog, WorkStatus } from '../types';

interface CalendarProps {
  logs: WorkLog[];
  year: number;
  month: number;
  onDateClick?: (date: Date) => void;
}

const Calendar: React.FC<CalendarProps> = ({ logs, year, month, onDateClick }) => {
  const daysInMonth = new Date(year, month, 0).getDate();
  const firstDayOfMonth = new Date(year, month - 1, 1).getDay();

  const days = Array.from({ length: daysInMonth }, (_, i) => i + 1);
  const blanks = Array.from({ length: firstDayOfMonth }, (_, i) => i);

  const getLogForDay = (day: number) => {
    const dateStr = `${year}-${String(month).padStart(2, '0')}-${String(day).padStart(2, '0')}`;
    return logs.find(l => {
      // Basic date string match
      const logDate = new Date(l.date);
      return logDate.getDate() === day && (logDate.getMonth() + 1) === month && logDate.getFullYear() === year;
    });
  };

  const getStatusColor = (status?: WorkStatus) => {
    switch (status) {
      case WorkStatus.WORKING: return 'bg-emerald-500 text-white';
      case WorkStatus.LEAVE: return 'bg-rose-500 text-white';
      case WorkStatus.HOLIDAY: return 'bg-amber-500 text-white';
      default: return 'bg-white border text-slate-400';
    }
  };

  return (
    <div className="bg-white rounded-xl shadow-sm border overflow-hidden">
      <div className="grid grid-cols-7 border-b">
        {['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'].map(d => (
          <div key={d} className="py-3 text-center text-xs font-bold text-slate-500 uppercase tracking-wider">
            {d}
          </div>
        ))}
      </div>
      <div className="grid grid-cols-7">
        {blanks.map(b => (
          <div key={`blank-${b}`} className="h-24 sm:h-32 border-b border-r bg-slate-50/50"></div>
        ))}
        {days.map(day => {
          const log = getLogForDay(day);
          return (
            <div
              key={day}
              onClick={() => onDateClick?.(new Date(year, month - 1, day))}
              className="h-24 sm:h-32 border-b border-r p-2 hover:bg-slate-50 cursor-pointer transition-colors relative group"
            >
              <div className="flex justify-between items-start">
                <span className={`text-sm font-medium w-7 h-7 flex items-center justify-center rounded-full ${log ? getStatusColor(log.status) : 'text-slate-700'}`}>
                  {day}
                </span>
                {log && (
                  <div className="hidden sm:block">
                    <span className="text-[10px] font-bold uppercase text-slate-400">
                      {log.status === WorkStatus.WORKING ? 'WRK' : log.status === WorkStatus.LEAVE ? 'LV' : 'HOL'}
                    </span>
                  </div>
                )}
              </div>
              {log && (
                <div className="mt-2 space-y-1">
                  <div className="text-[10px] font-semibold text-slate-800 truncate" title={log.village}>{log.village}</div>
                  <div className="text-[10px] text-slate-500 line-clamp-2" title={log.activity}>{log.activity}</div>
                </div>
              )}
              {!log && <div className="absolute inset-0 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity">
                <i className="fas fa-plus text-slate-300"></i>
              </div>}
            </div>
          );
        })}
      </div>
    </div>
  );
};

export default Calendar;

