import React, { useState, useEffect } from 'react';
import { useAuth } from '../App';
import { apiService } from '../services/apiService';
import { WorkLog, WorkStatus } from '../types';

const ReportsPage: React.FC = () => {
  const { auth } = useAuth();
  const [selectedMonth, setSelectedMonth] = useState(new Date().getMonth() + 1);
  const [selectedYear, setSelectedYear] = useState(new Date().getFullYear());
  const [reportLogs, setReportLogs] = useState<WorkLog[]>([]);
  const [loading, setLoading] = useState(false);

  const months = [
    'January', 'February', 'March', 'April', 'May', 'June',
    'July', 'August', 'September', 'October', 'November', 'December'
  ];

  useEffect(() => {
    generateReport();
  }, [selectedMonth, selectedYear]);

  const generateReport = async () => {
    setLoading(true);
    // 26th of prev month to 25th of current month
    const prevMonth = selectedMonth === 1 ? 12 : selectedMonth - 1;
    const prevYear = selectedMonth === 1 ? selectedYear - 1 : selectedYear;

    const allLogs = await apiService.getAllLogs();

    const filtered = allLogs.filter(l => {
        if (l.username !== auth.user?.username) return false;
        const d = new Date(l.date);
        const day = d.getDate();
        const m = d.getMonth() + 1;
        const y = d.getFullYear();

        // Check if date is between 26th of prev month and 25th of selected month
        const logDate = new Date(y, m - 1, day);
        const startDate = new Date(prevYear, prevMonth - 1, 26);
        const endDate = new Date(selectedYear, selectedMonth - 1, 25);

        return logDate >= startDate && logDate <= endDate;
    });

    setReportLogs(filtered.sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime()));
    setLoading(false);
  };

  const handlePrint = () => {
    window.print();
  };

  const stats = {
    working: reportLogs.filter(l => l.status === WorkStatus.WORKING).length,
    leave: reportLogs.filter(l => l.status === WorkStatus.LEAVE).length,
    holiday: reportLogs.filter(l => l.status === WorkStatus.HOLIDAY).length,
  };

  return (
    <div className="max-w-7xl mx-auto px-4 py-8">
      <div className="flex justify-between items-center mb-8 no-print">
        <div>
          <h1 className="text-3xl font-bold text-slate-900">Workdone Report</h1>
          <p className="text-slate-500">Period: 26th Prev Month → 25th Selected Month</p>
        </div>
        <button
          onClick={handlePrint}
          className="px-6 py-2.5 bg-slate-900 text-white rounded-xl font-bold hover:bg-slate-800 transition-all"
        >
          <i className="fas fa-download mr-2"></i> Download PDF
        </button>
      </div>

