/**
 * GOOGLE APPS SCRIPT BACKEND SETUP INSTRUCTIONS:
 * 1. Create a Google Sheet with tabs: "Users", "Work_Log", "Gallery".
 * 2. Deploy your script as a Web App (Access: Anyone).
 * 3. Paste the URL in the GAS_WEBAPP_URL variable below.
 */

// IMPORTANT: Set this to your actual Google Apps Script URL.
// If left empty or using the placeholder, the app runs in "Mock Mode" using LocalStorage.
const GAS_WEBAPP_URL: string = ""; 

// Automatically enable Mock Mode if no valid URL is provided
const isMockMode = !GAS_WEBAPP_URL || GAS_WEBAPP_URL.includes("macros/s/REPLACE_WITH_ID");

export const apiService = {
  async login(username: string, password: string): Promise<User | null> {
    if (isMockMode) {
      console.log("Running in Mock Mode - Login");
      if (username === 'admin' && password === 'admin') {
        return { username: 'admin', role: Role.ADMIN };
      }
      const mockUsers = JSON.parse(localStorage.getItem('mock_users') || '[]');
      const user = mockUsers.find((u: any) => u.username === username && u.password === password);
      return user ? { username: user.username, role: user.role } : null;
    }

    try {
      const resp = await fetch(`${GAS_WEBAPP_URL}?action=login&username=${encodeURIComponent(username)}&password=${encodeURIComponent(password)}`);
      if (!resp.ok) throw new Error("Network response was not ok");
      const data = await resp.json();
      return data.success ? data.user : null;
    } catch (err) {
      console.error("Login Error:", err);
      return null;
    }
  },

  async logWork(log: WorkLog): Promise<boolean> {
    if (isMockMode) {
      const logs = JSON.parse(localStorage.getItem('mock_logs') || '[]');
      logs.push({ ...log, timestamp: new Date().toISOString() });
      localStorage.setItem('mock_logs', JSON.stringify(logs));
      return true;
    }

    try {
      const resp = await fetch(GAS_WEBAPP_URL, {
        method: 'POST',
        body: JSON.stringify({ action: 'logWork', ...log })
      });
      const data = await resp.json();
      return data.success;
    } catch (err) {
      console.error("Log Work Error:", err);
      return false;
    }
  },

  async getAttendance(username: string, month: number, year: number): Promise<WorkLog[]> {
    if (isMockMode) {
      const logs = JSON.parse(localStorage.getItem('mock_logs') || '[]');
      return logs.filter((l: WorkLog) => {
        const d = new Date(l.date);
        return l.username === username && (d.getMonth() + 1) === month && d.getFullYear() === year;
      });
    }

    try {
      const resp = await fetch(`${GAS_WEBAPP_URL}?action=getAttendance&username=${username}&month=${month}&year=${year}`);
      const data = await resp.json();
      return data.logs || [];
    } catch (err) {
      console.error("Fetch Attendance Error:", err);
      return [];
    }
  },

  async getAllLogs(): Promise<WorkLog[]> {
    if (isMockMode) {
      return JSON.parse(localStorage.getItem('mock_logs') || '[]');
    }
    try {
      const resp = await fetch(`${GAS_WEBAPP_URL}?action=getAllLogs`);
      const data = await resp.json();
      return data.logs || [];
    } catch (err) {
      console.error("Fetch All Logs Error:", err);
      return [];
    }
  },

  async addUser(user: User): Promise<boolean> {
    if (isMockMode) {
      const users = JSON.parse(localStorage.getItem('mock_users') || '[]');
      users.push({ ...user, createdDate: new Date().toISOString() });
      localStorage.setItem('mock_users', JSON.stringify(users));
      return true;
    }
    try {
      const resp = await fetch(GAS_WEBAPP_URL, {
        method: 'POST',
        body: JSON.stringify({ action: 'addUser', ...user })
      });
      const data = await resp.json();
      return data.success;
    } catch (err) {
      console.error("Add User Error:", err);
      return false;
    }
  },

  async getAllUsers(): Promise<User[]> {
    if (isMockMode) {
      const users = JSON.parse(localStorage.getItem('mock_users') || '[]');
      return [{ username: 'admin', role: Role.ADMIN }, ...users];
    }
    try {
      const resp = await fetch(`${GAS_WEBAPP_URL}?action=getUsers`);
      const data = await resp.json();
      return data.users || [];
    } catch (err) {
      console.error("Fetch Users Error:", err);
      return [{ username: 'admin', role: Role.ADMIN }];
    }
  }
};

import React, { useState, useEffect } from 'react';
