import React, { useState, useEffect, createContext, useContext } from 'react';
import { HashRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import { AuthState, User, Role } from './types';
import Navbar from './components/Navbar';
import HomePage from './pages/HomePage';
import LoginPage from './pages/LoginPage';
import StaffDashboard from './pages/StaffDashboard';
import AdminDashboard from './pages/AdminDashboard';
import LogWorkForm from './pages/LogWorkForm';
import ReportsPage from './pages/ReportsPage';
import UserManagement from './pages/UserManagement';

interface AuthContextType {
  auth: AuthState;
  login: (user: User) => void;
  logout: () => void;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

export const useAuth = () => {
  const context = useContext(AuthContext);
  if (!context) throw new Error("useAuth must be used within AuthProvider");
  return context;
};

const ProtectedRoute = ({ children, allowedRoles }: React.PropsWithChildren<{ allowedRoles?: Role[] }>) => {
  const { auth } = useAuth();

  if (!auth.isAuthenticated || !auth.user) {
    return <Navigate to="/login" />;
  }

  if (allowedRoles) {
    const userRoleLower = auth.user.role.toLowerCase();
    const isAllowed = allowedRoles.some(role => role.toLowerCase() === userRoleLower);

    if (!isAllowed) {
      return <Navigate to="/dashboard" />;
    }
  }

  return <>{children}</>;
};

const App: React.FC = () => {
  const [auth, setAuth] = useState<AuthState>(() => {
    const saved = localStorage.getItem('wassan_auth');
    return saved ? JSON.parse(saved) : { user: null, isAuthenticated: false };
  });

  const login = (user: User) => {
    const newState = { user, isAuthenticated: true };
    setAuth(newState);
    localStorage.setItem('wassan_auth', JSON.stringify(newState));
  };

  const logout = () => {
    setAuth({ user: null, isAuthenticated: false });
    localStorage.removeItem('wassan_auth');
  };

  const isAdmin = auth.user?.role.toLowerCase() === Role.ADMIN.toLowerCase();

  return (
    <AuthContext.Provider value={{ auth, login, logout }}>
      <Router>
        <div className="min-h-screen flex flex-col">
          <Navbar />
          <main className="flex-grow">
            <Routes>
              <Route path="/" element={<HomePage />} />
              <Route path="/login" element={auth.isAuthenticated ? <Navigate to="/dashboard" /> : <LoginPage />} />

              <Route path="/dashboard" element={
                <ProtectedRoute>
                  {isAdmin ? <AdminDashboard /> : <StaffDashboard />}
                </ProtectedRoute>
              } />

              <Route path="/log-work" element={
                <ProtectedRoute allowedRoles={[Role.CLUSTER_FRP, Role.FRP, Role.CRP, Role.PROJECT_STAFF, Role.ADMIN]}>
                  <LogWorkForm />
                </ProtectedRoute>
              } />

              <Route path="/reports" element={
                <ProtectedRoute>
                  <ReportsPage />
                </ProtectedRoute>
              } />

              <Route path="/admin/users" element={
                <ProtectedRoute allowedRoles={[Role.ADMIN]}>
                  <UserManagement />
                </ProtectedRoute>
              } />

              <Route path="*" element={<Navigate to="/" />} />
            </Routes>
          </main>
          <footer className="bg-slate-900 text-white py-6 text-center text-sm">
            <p>&copy; 2024 Wassan Vikarabad Field Operations Monitoring. All Rights Reserved.</p>
          </footer>
        </div>
      </Router>
    </AuthContext.Provider>
  );
};

export default App;

import { User, WorkLog, Role, WorkStatus } from '../types';

const GAS_WEBAPP_URL: string = "https://script.google.com/macros/s/AKfycbxIvWtP7mohEMsKpqlyN4xnsu_9m6BOj2TblT63ldMftgCVxbrRQs9ee0jmuxdbcu3wmg/exec"; 

const isMockMode = !GAS_WEBAPP_URL || GAS_WEBAPP_URL.trim() === "" || GAS_WEBAPP_URL.includes("REPLACE_WITH_ID");

export const apiService = {
  async login(username: string, password: string): Promise<User | null> {
    if (isMockMode) {
      if (username === 'admin' && password === 'admin') {
        return { username: 'admin', role: Role.ADMIN };
      }
      const mockUsers = JSON.parse(localStorage.getItem('mock_users') || '[]');
      const user = mockUsers.find((u: any) => u.username === username && u.password === password);
      return user ? { username: user.username, role: user.role } : null;
    }

    try {
      const resp = await fetch(`${GAS_WEBAPP_URL}?action=login&username=${encodeURIComponent(username)}&password=${encodeURIComponent(password)}`, {
        method: 'GET',
        mode: 'cors',
        cache: 'no-cache'
      });
      if (!resp.ok) throw new Error("Network response was not ok");
      const data = await resp.json();
      return data.success ? data.user : null;
    } catch (err) {
      console.error("Login Error:", err);
      return null;
    }
  },

  async logWork(log: WorkLog): Promise<boolean> {
    if (isMockMode) {
      const logs = JSON.parse(localStorage.getItem('mock_logs') || '[]');
      logs.push({ ...log, timestamp: new Date().toISOString() });
      localStorage.setItem('mock_logs', JSON.stringify(logs));
      return true;
    }

    try {
      const payload = {
        action: 'logWork',
        ...log,
        timestamp: new Date().toISOString()
      };

      await fetch(GAS_WEBAPP_URL, {
        method: 'POST',
        mode: 'no-cors',
        body: JSON.stringify(payload)
      });

      return true; 
    } catch (err) {
      console.error("Log Work Submission Error:", err);
      return false;
    }
  },

  async getAttendance(username: string, month: number, year: number): Promise<WorkLog[]> {
    if (isMockMode) {
      const logs = JSON.parse(localStorage.getItem('mock_logs') || '[]');
      return logs.filter((l: WorkLog) => {
        const d = new Date(l.date);
        return l.username === username && (d.getMonth() + 1) === month && d.getFullYear() === year;
      });
    }

    try {
      const resp = await fetch(`${GAS_WEBAPP_URL}?action=getAttendance&username=${encodeURIComponent(username)}&month=${month}&year=${year}`);
      const data = await resp.json();
      return data.logs || [];
    } catch (err) {
      console.error("Fetch Attendance Error:", err);
      return [];
    }
  },

  async getAllLogs(): Promise<WorkLog[]> {
    if (isMockMode) {
      return JSON.parse(localStorage.getItem('mock_logs') || '[]');
    }
    try {
      const resp = await fetch(`${GAS_WEBAPP_URL}?action=getAllLogs`);
      const data = await resp.json();
      return data.logs || [];
    } catch (err) {
      console.error("Fetch All Logs Error:", err);
      return [];
    }
  },

  async addUser(user: User): Promise<boolean> {
    if (isMockMode) {
      const users = JSON.parse(localStorage.getItem('mock_users') || '[]');
      users.push({ ...user, createdDate: new Date().toISOString() });
      localStorage.setItem('mock_users', JSON.stringify(users));
      return true;
    }
    try {
      const resp = await fetch(GAS_WEBAPP_URL, {
        method: 'POST',
        body: JSON.stringify({ action: 'addUser', ...user })
      });
      const data = await resp.json();
      return data.success;
    } catch (err) {
      console.error("Add User Error:", err);
      return false;
    }
  },

  async getAllUsers(): Promise<User[]> {
    if (isMockMode) {
      const users = JSON.parse(localStorage.getItem('mock_users') || '[]');
      return [{ username: 'admin', role: Role.ADMIN }, ...users];
    }
    try {
      const resp = await fetch(`${GAS_WEBAPP_URL}?action=getUsers`);
      const data = await resp.json();
      return data.users || [];
    } catch (err) {
      console.error("Fetch Users Error:", err);
      return [{ username: 'admin', role: Role.ADMIN }];
    }
  }
};

import { GoogleGenAI } from "@google/genai";
import { WorkLog } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const geminiService = {
  async analyzeWorkLogs(logs: WorkLog[], userName: string): Promise<string> {
    if (!logs.length) return "No data available for analysis.";

    const context = logs.map(l => 
      `Date: ${l.date}, Village: ${l.village}, Activity: ${l.activity}, Details: ${l.workDetails}, Status: ${l.status}`
    ).join('\n');

    try {
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Analyze the following field activity logs for ${userName} and provide a professional performance summary, highlighting key accomplishments and identifying any patterns in activities or village coverage. Keep it under 150 words.\n\nLogs:\n${context}`,
        config: {
          systemInstruction: "You are an expert field operations analyst. Provide insightful, constructive feedback based on data."
        }
      });
      return response.text || "Unable to generate analysis at this time.";
    } catch (err) {
      console.error("Gemini Error:", err);
      return "AI analysis is currently unavailable.";
    }
  }
};

