                    {loading ? 'Processing data...' : 'No entries found for this reporting period.'}
                  </td>
                </tr>
              )}
              {/* Fill remaining space to match the physical document look */}
              {reportLogs.length < 15 && Array.from({ length: 15 - reportLogs.length }).map((_, i) => (
