    const success = await apiService.addUser(newUser as User);
    setLoading(false);

    if (success) {
      alert("User added successfully to the 'Users' sheet!");
      setNewUser({ username: '', password: '', role: Role.CRP });
      setShowAdd(false);
      fetchUsers();
